import React, { useState, useCallback } from 'react';
import {
  Box,
  Typography,
  Button,
  Grid,
  IconButton,
  Tooltip,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogContentText,
  DialogActions,
} from '@mui/material';
import AddIcon from '@mui/icons-material/Add';
import EditIcon from '@mui/icons-material/Edit';
import DeleteIcon from '@mui/icons-material/Delete';
import StoreIcon from '@mui/icons-material/Store';
import { useNavigate } from 'react-router-dom';
import { useBrandStore } from '@/shared/stores/brandStore';
import BrandCard from './BrandCard';
import BrandFormDialog from './BrandFormDialog';
import BrandDeleteDialog from './BrandDeleteDialog';
import type { Brand } from '@/shared/types/brand';

/** Brand list page with grid of brand cards and CRUD operations */
const BrandListPage: React.FC = () => {
  const navigate = useNavigate();
  const brands = useBrandStore((s) => s.brands);
  const addBrand = useBrandStore((s) => s.addBrand);
  const updateBrand = useBrandStore((s) => s.updateBrand);
  const deleteBrand = useBrandStore((s) => s.deleteBrand);
  const switchBrand = useBrandStore((s) => s.switchBrand);

  const [formOpen, setFormOpen] = useState(false);
  const [formMode, setFormMode] = useState<'create' | 'edit'>('create');
  const [editingBrand, setEditingBrand] = useState<Brand | null>(null);

  const [deleteOpen, setDeleteOpen] = useState(false);
  const [deletingBrand, setDeletingBrand] = useState<Brand | null>(null);

  const handleEnter = useCallback(
    (brandId: string) => {
      switchBrand(brandId);
      navigate('/dashboard');
    },
    [switchBrand, navigate],
  );

  const handleCreate = () => {
    setFormMode('create');
    setEditingBrand(null);
    setFormOpen(true);
  };

  const handleEdit = (brand: Brand) => {
    setFormMode('edit');
    setEditingBrand(brand);
    setFormOpen(true);
  };

  const handleDeleteClick = (brand: Brand) => {
    setDeletingBrand(brand);
    setDeleteOpen(true);
  };

  const handleFormSave = async (brand: Brand) => {
    if (formMode === 'create') {
      await addBrand(brand);
    } else {
      await updateBrand(brand.id, brand);
    }
    setFormOpen(false);
  };

  const handleDeleteConfirm = async () => {
    if (deletingBrand) {
      await deleteBrand(deletingBrand.id);
    }
    setDeleteOpen(false);
    setDeletingBrand(null);
  };

  // Empty state
  if (brands.length === 0) {
    return (
      <Box
        sx={{
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          height: '100%',
          gap: 3,
        }}
      >
        <StoreIcon sx={{ fontSize: 80, color: 'text.secondary', opacity: 0.5 }} />
        <Box sx={{ textAlign: 'center' }}>
          <Typography variant="h5" fontWeight={700} gutterBottom>
            创建第一个品牌
          </Typography>
          <Typography variant="body1" color="text.secondary" sx={{ maxWidth: 400 }}>
            品牌是 VOS 的核心管理单元，为每个品牌创建独立的数据空间、知识库和策略卡
          </Typography>
        </Box>
        <Button
          variant="contained"
          size="large"
          startIcon={<AddIcon />}
          onClick={handleCreate}
        >
          新建品牌
        </Button>
      </Box>
    );
  }

  return (
    <Box>
      {/* Page header */}
      <Box
        sx={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          mb: 3,
        }}
      >
        <Box>
          <Typography variant="h5" fontWeight={700}>
            品牌管理
          </Typography>
          <Typography variant="body2" color="text.secondary">
            管理所有品牌空间，共 {brands.length} 个品牌
          </Typography>
        </Box>
        <Button
          variant="contained"
          startIcon={<AddIcon />}
          onClick={handleCreate}
        >
          新建品牌
        </Button>
      </Box>

      {/* Brand cards grid */}
      <Grid container spacing={2.5}>
        {brands.map((brand) => (
          <Grid item xs={12} sm={6} md={4} lg={3} key={brand.id}>
            <Box sx={{ position: 'relative' }}>
              {/* Action buttons overlay */}
              <Box
                sx={{
                  position: 'absolute',
                  top: 8,
                  right: 8,
                  zIndex: 1,
                  display: 'flex',
                  gap: 0.5,
                }}
              >
                <Tooltip title="编辑品牌">
                  <IconButton
                    size="small"
                    onClick={(e) => {
                      e.stopPropagation();
                      handleEdit(brand);
                    }}
                    sx={{
                      bgcolor: 'background.paper',
                      '&:hover': { bgcolor: 'action.hover' },
                    }}
                  >
                    <EditIcon fontSize="small" />
                  </IconButton>
                </Tooltip>
                <Tooltip title="删除品牌">
                  <IconButton
                    size="small"
                    onClick={(e) => {
                      e.stopPropagation();
                      handleDeleteClick(brand);
                    }}
                    sx={{
                      bgcolor: 'background.paper',
                      '&:hover': { bgcolor: 'error.main', color: '#fff' },
                    }}
                  >
                    <DeleteIcon fontSize="small" />
                  </IconButton>
                </Tooltip>
              </Box>
              <BrandCard brand={brand} onEnter={handleEnter} />
            </Box>
          </Grid>
        ))}
      </Grid>

      {/* Create/Edit dialog */}
      <BrandFormDialog
        open={formOpen}
        mode={formMode}
        brand={editingBrand}
        onClose={() => setFormOpen(false)}
        onSave={handleFormSave}
      />

      {/* Delete dialog */}
      <BrandDeleteDialog
        open={deleteOpen}
        brandName={deletingBrand?.name || ''}
        onClose={() => {
          setDeleteOpen(false);
          setDeletingBrand(null);
        }}
        onConfirm={handleDeleteConfirm}
      />
    </Box>
  );
};

export default BrandListPage;
