import React, { useState } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Button,
  Typography,
  TextField,
  Box,
  Alert,
} from '@mui/material';
import WarningAmberIcon from '@mui/icons-material/WarningAmber';

interface BrandDeleteDialogProps {
  open: boolean;
  brandName: string;
  onClose: () => void;
  onConfirm: () => void;
}

/** Delete confirmation dialog with double confirmation */
const BrandDeleteDialog: React.FC<BrandDeleteDialogProps> = ({
  open,
  brandName,
  onClose,
  onConfirm,
}) => {
  const [confirmText, setConfirmText] = useState('');

  const handleConfirm = () => {
    if (confirmText === brandName) {
      onConfirm();
      setConfirmText('');
    }
  };

  const handleClose = () => {
    setConfirmText('');
    onClose();
  };

  return (
    <Dialog
      open={open}
      onClose={handleClose}
      maxWidth="sm"
      fullWidth
      PaperProps={{ sx: { borderRadius: 3 } }}
    >
      <DialogTitle sx={{ display: 'flex', alignItems: 'center', gap: 1.5, fontWeight: 700 }}>
        <WarningAmberIcon color="warning" />
        删除品牌
      </DialogTitle>
      <DialogContent>
        <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
          <Alert severity="error" variant="outlined">
            <Typography variant="body2" fontWeight={600}>
              确定删除「{brandName}」？
            </Typography>
            <Typography variant="body2">
              所有评论和分析数据将被永久删除，此操作不可撤销。
            </Typography>
          </Alert>
          <Typography variant="body2" color="text.secondary">
            请输入品牌名称「<strong>{brandName}</strong>」以确认删除：
          </Typography>
          <TextField
            value={confirmText}
            onChange={(e) => setConfirmText(e.target.value)}
            placeholder={brandName}
            fullWidth
            autoFocus
            error={confirmText.length > 0 && confirmText !== brandName}
            helperText={
              confirmText.length > 0 && confirmText !== brandName
                ? '品牌名称不匹配'
                : ''
            }
          />
        </Box>
      </DialogContent>
      <DialogActions sx={{ px: 3, py: 2 }}>
        <Button onClick={handleClose} color="inherit">
          取消
        </Button>
        <Button
          onClick={handleConfirm}
          variant="contained"
          color="error"
          disabled={confirmText !== brandName}
        >
          确认删除
        </Button>
      </DialogActions>
    </Dialog>
  );
};

export default BrandDeleteDialog;
