import React, { useState, useEffect, useCallback } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  Button,
  MenuItem,
  Box,
  Typography,
} from '@mui/material';
import { nanoid } from 'nanoid';
import type { Brand } from '@/shared/types/brand';
import type { Category } from '@/shared/types/category';
import { db } from '@/shared/db/db';

interface BrandFormDialogProps {
  open: boolean;
  mode: 'create' | 'edit';
  brand?: Brand | null;
  onClose: () => void;
  onSave: (brand: Brand) => void;
}

const emptyForm = {
  name: '',
  industry: '',
  categoryId: '',
  description: '',
  logoUrl: '',
};

const defaultConfig: Brand['config'] = {
  products: [],
  brandStory: '',
  visualStyle: '',
  tone: '',
  keywords: {
    brandWords: [],
    categoryWords: [],
    sceneWords: [],
    audienceWords: [],
  },
  contentGuidelines: {
    do: [],
    dont: [],
  },
};

const defaultStats: Brand['stats'] = {
  totalComments: 0,
  confirmedInsights: 0,
  strategyCards: { total: 0, active: 0, draft: 0, archived: 0 },
  lastImportAt: null,
};

/** Dialog for creating or editing a brand */
const BrandFormDialog: React.FC<BrandFormDialogProps> = ({
  open,
  mode,
  brand,
  onClose,
  onSave,
}) => {
  const [form, setForm] = useState(emptyForm);
  const [categories, setCategories] = useState<Category[]>([]);
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Load categories for the dropdown
  useEffect(() => {
    if (open) {
      db.categories.toArray().then(setCategories).catch(console.error);
    }
  }, [open]);

  // Pre-fill form in edit mode
  useEffect(() => {
    if (brand && mode === 'edit') {
      setForm({
        name: brand.name || '',
        industry: brand.industry || '',
        categoryId: brand.categoryId || '',
        description: '',
        logoUrl: brand.logoUrl || '',
      });
    } else {
      setForm(emptyForm);
    }
    setErrors({});
  }, [brand, mode, open]);

  const handleChange = useCallback(
    (field: string) => (e: React.ChangeEvent<HTMLInputElement>) => {
      setForm((prev) => ({ ...prev, [field]: e.target.value }));
      setErrors((prev) => ({ ...prev, [field]: '' }));
    },
    [],
  );

  const validate = (): boolean => {
    const newErrors: Record<string, string> = {};
    if (!form.name.trim()) {
      newErrors.name = '品牌名不能为空';
    }
    if (!form.industry.trim()) {
      newErrors.industry = '行业不能为空';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSave = () => {
    if (!validate()) return;

    if (mode === 'create') {
      const newBrand: Brand = {
        id: `brand_${nanoid(8)}`,
        name: form.name.trim(),
        industry: form.industry.trim(),
        categoryId: form.categoryId || null,
        logoUrl: form.logoUrl.trim(),
        createdAt: new Date().toISOString(),
        config: { ...defaultConfig },
        competitors: [],
        stats: { ...defaultStats },
      };
      onSave(newBrand);
    } else if (brand) {
      const updated: Brand = {
        ...brand,
        name: form.name.trim(),
        industry: form.industry.trim(),
        categoryId: form.categoryId || null,
        logoUrl: form.logoUrl.trim(),
      };
      onSave(updated);
    }
  };

  return (
    <Dialog
      open={open}
      onClose={onClose}
      maxWidth="sm"
      fullWidth
      PaperProps={{
        sx: { borderRadius: 3 },
      }}
    >
      <DialogTitle sx={{ fontWeight: 700 }}>
        {mode === 'create' ? '新建品牌' : '编辑品牌'}
      </DialogTitle>
      <DialogContent dividers>
        <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2.5, pt: 1 }}>
          <TextField
            label="品牌名称"
            value={form.name}
            onChange={handleChange('name')}
            error={!!errors.name}
            helperText={errors.name}
            required
            fullWidth
            autoFocus
            placeholder="例如：轻氧护肤"
          />
          <TextField
            label="所属行业"
            value={form.industry}
            onChange={handleChange('industry')}
            error={!!errors.industry}
            helperText={errors.industry}
            required
            fullWidth
            placeholder="例如：新消费护肤"
          />
          <TextField
            label="关联品类"
            value={form.categoryId}
            onChange={handleChange('categoryId')}
            select
            fullWidth
          >
            <MenuItem value="">
              <Typography color="text.secondary">— 不关联 —</Typography>
            </MenuItem>
            {categories.map((cat) => (
              <MenuItem key={cat.id} value={cat.id}>
                {cat.name}
              </MenuItem>
            ))}
          </TextField>
          <TextField
            label="品牌描述"
            value={form.description}
            onChange={handleChange('description')}
            fullWidth
            multiline
            minRows={2}
            maxRows={4}
            placeholder="简要描述品牌定位、目标人群等"
          />
          <TextField
            label="Logo URL"
            value={form.logoUrl}
            onChange={handleChange('logoUrl')}
            fullWidth
            placeholder="https://example.com/logo.png"
            helperText="可选，输入品牌 Logo 的图片地址"
          />
        </Box>
      </DialogContent>
      <DialogActions sx={{ px: 3, py: 2 }}>
        <Button onClick={onClose} color="inherit">
          取消
        </Button>
        <Button onClick={handleSave} variant="contained">
          {mode === 'create' ? '创建品牌' : '保存修改'}
        </Button>
      </DialogActions>
    </Dialog>
  );
};

export default BrandFormDialog;
