import React from 'react';
import {
  Card,
  CardContent,
  CardActions,
  Typography,
  Button,
  Chip,
  Box,
  Stack,
} from '@mui/material';
import ArrowForwardIcon from '@mui/icons-material/ArrowForward';
import ForumIcon from '@mui/icons-material/Forum';
import LayersIcon from '@mui/icons-material/Layers';
import type { Brand } from '@/shared/types/brand';

interface BrandCardProps {
  brand: Brand;
  onEnter: (brandId: string) => void;
}

/** Display a single brand as a card with stats and enter button */
const BrandCard: React.FC<BrandCardProps> = ({ brand, onEnter }) => {
  return (
    <Card
      sx={{
        height: '100%',
        display: 'flex',
        flexDirection: 'column',
        transition: 'transform 0.2s, box-shadow 0.2s',
        '&:hover': {
          transform: 'translateY(-2px)',
          boxShadow: 4,
        },
      }}
    >
      <CardContent sx={{ flexGrow: 1 }}>
        <Stack spacing={1.5}>
          {/* Header row: name + industry */}
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            {brand.logoUrl ? (
              <Box
                component="img"
                src={brand.logoUrl}
                alt={brand.name}
                sx={{
                  width: 40,
                  height: 40,
                  borderRadius: 2,
                  objectFit: 'cover',
                }}
              />
            ) : (
              <Box
                sx={{
                  width: 40,
                  height: 40,
                  borderRadius: 2,
                  bgcolor: 'primary.main',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  color: '#fff',
                  fontWeight: 700,
                  fontSize: 18,
                  flexShrink: 0,
                }}
              >
                {brand.name.charAt(0)}
              </Box>
            )}
            <Box sx={{ minWidth: 0 }}>
              <Typography
                variant="subtitle1"
                fontWeight={600}
                noWrap
                title={brand.name}
              >
                {brand.name}
              </Typography>
              <Typography variant="body2" color="text.secondary" noWrap>
                {brand.industry || '未设置行业'}
              </Typography>
            </Box>
          </Box>

          {/* Stats */}
          <Stack direction="row" spacing={2}>
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
              <ForumIcon sx={{ fontSize: 16, color: 'text.secondary' }} />
              <Typography variant="body2" color="text.secondary">
                {brand.stats?.totalComments ?? 0} 评论
              </Typography>
            </Box>
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
              <LayersIcon sx={{ fontSize: 16, color: 'text.secondary' }} />
              <Typography variant="body2" color="text.secondary">
                {brand.stats?.strategyCards?.total ?? 0} 策略卡
              </Typography>
            </Box>
          </Stack>

          {/* Category chip */}
          {brand.categoryId && (
            <Box>
              <Chip
                label={brand.categoryId}
                size="small"
                variant="outlined"
                sx={{ fontSize: 11 }}
              />
            </Box>
          )}
        </Stack>
      </CardContent>

      <CardActions sx={{ px: 2, pb: 2, pt: 0 }}>
        <Button
          variant="contained"
          size="small"
          endIcon={<ArrowForwardIcon />}
          onClick={() => onEnter(brand.id)}
          fullWidth
        >
          进入
        </Button>
      </CardActions>
    </Card>
  );
};

export default BrandCard;
